import React, { useEffect, useState } from 'react';
import { useAuth } from '../context/AuthContext';
import { listenAuction, placeBid, listenPlayers, listenRecords, logoutPlayer } from '../firebase/services';
import Countdown from '../components/Countdown';
import toast from 'react-hot-toast';

const BID_INCREMENTS = [500, 1000, 1500];

export default function PlayerDashboard() {
  const { user, playerData } = useAuth();
  const [auction, setAuction] = useState(null);
  const [players, setPlayers] = useState([]);
  const [records, setRecords] = useState([]);
  const [selectedIncrement, setSelectedIncrement] = useState(500);
  const [bidding, setBidding] = useState(false);
  const [tab, setTab] = useState('auction');
  const [auctionLoaded, setAuctionLoaded] = useState(false);

  useEffect(() => {
    const unsubs = [
      listenAuction(data => { setAuction(data); setAuctionLoaded(true); }),
      listenPlayers(setPlayers),
      listenRecords(setRecords),
    ];
    return () => unsubs.forEach(u => u());
  }, []);

  const myNextBid = auction ? auction.currentBid + selectedIncrement : 0;
  const isMyTurn = auction?.currentBidder !== user?.uid;
  const iWon = auction?.result?.winnerId === user?.uid;
  const hasWon = playerData?.hasWon;
  const canBid = auction?.active && !auction?.closed && !hasWon && isMyTurn;
  const isCurrentLeader = auction?.currentBidder === user?.uid;

  const handleBid = async () => {
    if (!canBid) return;
    if (new Date() > new Date(auction.endsAt)) return toast.error('Auction has ended!');
    setBidding(true);
    try {
      await placeBid(user.uid, playerData.name, myNextBid);
      toast.success(`Bid of ₹${myNextBid.toLocaleString('en-IN')} placed!`);
    } catch (err) {
      toast.error(err.message);
    } finally {
      setBidding(false);
    }
  };

  const handleLogout = async () => { await logoutPlayer(); };

  const wonPlayers = players.filter(p => p.hasWon);
  const pendingPlayers = players.filter(p => !p.hasWon);

  return (
    <div className="page">
      {/* Navbar */}
      <nav className="navbar">
        <div>
          <div className="navbar-brand">🪙 BC Circle</div>
          <div className="navbar-sub">Welcome, {playerData?.name}</div>
        </div>
        <button className="btn btn-ghost btn-sm" onClick={handleLogout}>Logout</button>
      </nav>

      {/* Tabs */}
      <div className="tabs">
        <div className={`tab ${tab === 'auction' ? 'active' : ''}`} onClick={() => setTab('auction')}>🔴 Live</div>
        <div className={`tab ${tab === 'players' ? 'active' : ''}`} onClick={() => setTab('players')}>👥 Players</div>
        <div className={`tab ${tab === 'records' ? 'active' : ''}`} onClick={() => setTab('records')}>📋 Records</div>
      </div>

      {/* AUCTION TAB */}
      {tab === 'auction' && (
        <>
          {!auctionLoaded && <div className="spinner" />}

          {auctionLoaded && (!auction || (!auction.active && !auction.closed)) && (
            <div className="card" style={{ textAlign: 'center', padding: '40px 24px' }}>
              <div style={{ fontSize: '3rem', marginBottom: 16 }}>🌙</div>
              <h2 style={{ color: 'var(--gold)', marginBottom: 8 }}>No Active Auction</h2>
              <p style={{ color: 'var(--text-muted)', fontSize: '0.9rem' }}>
                Wait for the admin to start this month's bidding session.
              </p>
            </div>
          )}

          {auction?.closed && auction?.result && (
            <div className="winner-banner">
              <div className="winner-trophy">🏆</div>
              <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginBottom: 4, textTransform: 'uppercase', letterSpacing: '0.08em' }}>
                {auction.result.month} Winner
              </div>
              <div className="winner-name">{auction.result.winnerName}</div>
              <div className="winner-amount">₹{auction.result.winnerReceives?.toLocaleString('en-IN')}</div>
              <div style={{ color: 'var(--text-muted)', fontSize: '0.85rem', marginTop: 8 }}>
                Winning bid: ₹{auction.result.winningBid?.toLocaleString('en-IN')} •
                Bonus per player: ₹{auction.result.perPlayerBonus?.toLocaleString('en-IN')}
              </div>
              {iWon && (
                <div style={{ marginTop: 16, padding: '12px 20px', background: 'rgba(46,204,113,0.15)', borderRadius: 10, color: 'var(--green)', fontWeight: 600 }}>
                  🎉 Congratulations! You won this month!
                </div>
              )}
            </div>
          )}

          {auction?.active && !auction?.closed && (
            <>
              {/* Live Auction Header */}
              <div className="card">
                <div className="card-header">
                  <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                    <span className="status-dot live"></span>
                    <span className="card-title">Live Auction</span>
                  </div>
                  <span className="badge badge-gold">{auction.month}</span>
                </div>

                {/* Timer */}
                <div style={{ marginBottom: 20, textAlign: 'center' }}>
                  <Countdown endsAt={auction.endsAt} />
                  <div style={{ color: 'var(--text-muted)', fontSize: '0.75rem', marginTop: 4 }}>remaining</div>
                </div>

                {/* Pool info */}
                <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12, marginBottom: 20 }}>
                  <div style={{ background: 'var(--bg-raised)', borderRadius: 10, padding: '12px 14px', textAlign: 'center' }}>
                    <div style={{ color: 'var(--text-muted)', fontSize: '0.7rem', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 4 }}>Total Pool</div>
                    <div style={{ color: 'var(--gold)', fontWeight: 700, fontSize: '1.1rem', fontFamily: 'Playfair Display, serif' }}>
                      ₹{auction.totalPool?.toLocaleString('en-IN')}
                    </div>
                  </div>
                  <div style={{ background: 'var(--bg-raised)', borderRadius: 10, padding: '12px 14px', textAlign: 'center' }}>
                    <div style={{ color: 'var(--text-muted)', fontSize: '0.7rem', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 4 }}>Min Bid</div>
                    <div style={{ color: 'var(--text)', fontWeight: 600, fontSize: '1.1rem' }}>
                      ₹{auction.minBid?.toLocaleString('en-IN')}
                    </div>
                  </div>
                </div>

                {/* Current Bid */}
                <div style={{ textAlign: 'center', marginBottom: 24, padding: '20px 0', borderTop: '1px solid var(--border)', borderBottom: '1px solid var(--border)' }}>
                  <div style={{ color: 'var(--text-muted)', fontSize: '0.75rem', textTransform: 'uppercase', letterSpacing: '0.08em', marginBottom: 8 }}>Current Highest Bid</div>
                  <div className="bid-amount">
                    <span className="currency">₹</span>
                    {auction.currentBid?.toLocaleString('en-IN')}
                  </div>
                  {auction.currentBidderName && (
                    <div style={{ color: isCurrentLeader ? 'var(--green)' : 'var(--gold-light)', marginTop: 8, fontWeight: 500 }}>
                      {isCurrentLeader ? '🏅 You are leading!' : `by ${auction.currentBidderName}`}
                    </div>
                  )}
                  {auction.currentBid && (
                    <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem', marginTop: 6 }}>
                      Winner gets: <span style={{ color: 'var(--green)' }}>₹{(auction.totalPool - auction.currentBid).toLocaleString('en-IN')}</span>
                    </div>
                  )}
                </div>

                {/* Bidding UI */}
                {hasWon ? (
                  <div style={{ textAlign: 'center', padding: '16px', background: 'rgba(201,168,76,0.08)', borderRadius: 10, color: 'var(--gold)' }}>
                    🏆 You already won a previous month!
                  </div>
                ) : (
                  <>
                    <div style={{ marginBottom: 12 }}>
                      <div style={{ color: 'var(--text-muted)', fontSize: '0.75rem', textTransform: 'uppercase', letterSpacing: '0.06em', marginBottom: 8 }}>Select increment</div>
                      <div className="bid-options">
                        {BID_INCREMENTS.map(inc => (
                          <div
                            key={inc}
                            className={`bid-option ${selectedIncrement === inc ? 'selected' : ''}`}
                            onClick={() => setSelectedIncrement(inc)}
                          >
                            +₹{inc.toLocaleString('en-IN')}
                          </div>
                        ))}
                      </div>
                    </div>

                    <div style={{ textAlign: 'center', marginBottom: 12 }}>
                      <div style={{ color: 'var(--text-muted)', fontSize: '0.8rem' }}>Your bid will be</div>
                      <div style={{ color: 'var(--gold-light)', fontWeight: 700, fontSize: '1.3rem', fontFamily: 'Playfair Display, serif' }}>
                        ₹{myNextBid?.toLocaleString('en-IN')}
                      </div>
                    </div>

                    <button
                      className="btn btn-primary btn-full"
                      onClick={handleBid}
                      disabled={bidding || !canBid || isCurrentLeader}
                    >
                      {bidding ? 'Placing Bid...' :
                        isCurrentLeader ? '✓ You\'re Leading' :
                        `Place Bid ₹${myNextBid?.toLocaleString('en-IN')}`}
                    </button>
                  </>
                )}
              </div>

              {/* Bid History */}
              <div className="card">
                <div className="card-header">
                  <span className="card-title">Bid History</span>
                  <span className="badge badge-muted">{auction.bids?.length || 0} bids</span>
                </div>
                {(!auction.bids || auction.bids.length === 0) ? (
                  <div style={{ color: 'var(--text-muted)', textAlign: 'center', padding: '20px 0', fontSize: '0.9rem' }}>
                    No bids yet. Be the first!
                  </div>
                ) : (
                  [...auction.bids].reverse().map((bid, i) => (
                    <div className="bid-item" key={i}>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                        <div className="player-avatar" style={{ width: 28, height: 28, fontSize: '0.75rem' }}>
                          {bid.playerName?.[0]?.toUpperCase()}
                        </div>
                        <div>
                          <div style={{ fontWeight: 500, fontSize: '0.9rem' }}>{bid.playerName}</div>
                          <div style={{ color: 'var(--text-muted)', fontSize: '0.72rem' }}>
                            {new Date(bid.timestamp).toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit', second: '2-digit' })}
                          </div>
                        </div>
                      </div>
                      <div style={{ color: 'var(--gold)', fontWeight: 700, fontFamily: 'Playfair Display, serif' }}>
                        ₹{bid.amount?.toLocaleString('en-IN')}
                      </div>
                    </div>
                  ))
                )}
              </div>
            </>
          )}
        </>
      )}

      {/* PLAYERS TAB */}
      {tab === 'players' && (
        <>
          <div className="card">
            <div className="card-header">
              <span className="card-title">Pending Players</span>
              <span className="badge badge-red">{pendingPlayers.length}</span>
            </div>
            <div className="players-grid">
              {pendingPlayers.map(p => (
                <div className="player-chip" key={p.id}>
                  <div className="player-avatar">{p.name?.[0]?.toUpperCase()}</div>
                  <div>
                    <div style={{ fontWeight: 500, fontSize: '0.85rem' }}>{p.name}</div>
                    <span className="badge badge-muted" style={{ fontSize: '0.65rem' }}>Pending</span>
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div className="card">
            <div className="card-header">
              <span className="card-title">Won Players</span>
              <span className="badge badge-gold">{wonPlayers.length}</span>
            </div>
            <div className="players-grid">
              {wonPlayers.map(p => (
                <div className="player-chip won" key={p.id}>
                  <div className="player-avatar">🏆</div>
                  <div>
                    <div style={{ fontWeight: 500, fontSize: '0.85rem' }}>{p.name}</div>
                    <div style={{ color: 'var(--text-muted)', fontSize: '0.72rem' }}>{p.wonMonth}</div>
                  </div>
                </div>
              ))}
              {wonPlayers.length === 0 && (
                <div style={{ color: 'var(--text-muted)', fontSize: '0.85rem', padding: '8px 0', gridColumn: 'span 2' }}>No winners yet this cycle.</div>
              )}
            </div>
          </div>
        </>
      )}

      {/* RECORDS TAB */}
      {tab === 'records' && (
        <div className="card" style={{ overflowX: 'auto' }}>
          <div className="card-header">
            <span className="card-title">Monthly Records</span>
            <span className="badge badge-muted">{records.length} months</span>
          </div>
          {records.length === 0 ? (
            <div style={{ color: 'var(--text-muted)', textAlign: 'center', padding: '20px 0', fontSize: '0.9rem' }}>
              No records yet. First auction pending!
            </div>
          ) : (
            <table className="records-table">
              <thead>
                <tr>
                  <th>Month</th>
                  <th>Winner</th>
                  <th>Bid</th>
                  <th>Received</th>
                  <th>Bonus/Player</th>
                </tr>
              </thead>
              <tbody>
                {records.map(r => (
                  <tr key={r.id}>
                    <td><span className="badge badge-muted">{r.month}</span></td>
                    <td style={{ fontWeight: 500 }}>{r.winnerName || '—'}</td>
                    <td style={{ color: 'var(--accent)' }}>₹{r.winningBid?.toLocaleString('en-IN')}</td>
                    <td style={{ color: 'var(--green)', fontWeight: 600 }}>₹{r.winnerReceives?.toLocaleString('en-IN')}</td>
                    <td style={{ color: 'var(--gold)' }}>₹{r.perPlayerBonus?.toLocaleString('en-IN')}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          )}
        </div>
      )}
    </div>
  );
}
